        attractions_bovec_mangart_title: "Mangart Sattel",
        attractions_bovec_mangart_teaser: "Hochgebirgssattel mit spektakulären Ausblicken. Erreichbar über Bergwege oder mit dem Auto.",
        attractions_bovec_mangart_details: "Der Mangart Sattel ist ein Hochgebirgssattel mit spektakulären Ausblicken auf die umliegenden Berge und das Tal. Sie können den Sattel über Bergwege oder mit dem Auto auf der Straße erreichen. Die beste Zeit für einen Besuch ist Frühling oder Sommer, wenn das Wetter am schönsten ist. Bringen Sie bequeme Schuhe, zusätzliche Kleidung und viel Wasser mit. Das Wetter im Hochgebirge kann sich schnell ändern, seien Sie daher auf Änderungen vorbereitet.",
        attractions_bovec_mangart_time: "1-3 Stunden",
        attractions_bovec_mangart_difficulty: "attractions_difficulty_moderate",
        attractions_bovec_mangart_family: "attractions_family_care",
        attractions_trenta_dom_title: "Dom Trenta",
        attractions_trenta_dom_teaser: "Informationszentrum und Museum in Trenta. Große Option zum Kennenlernen des Tals.",
        attractions_trenta_dom_details: "Dom Trenta ist ein Informationszentrum und Museum in Trenta, das Möglichkeiten zum Kennenlernen des Tals und seiner Geschichte bietet. Das Zentrum bietet Ausstellungen, Informationen und Erholungsmöglichkeiten. Die beste Zeit für einen Besuch ist jederzeit, da das Zentrum in Innenräumen ist. Überprüfen Sie die Öffnungszeiten vor dem Besuch. Das Zentrum ist für Kinder geeignet und bietet interessante Ausstellungen für alle Altersgruppen.",
        attractions_trenta_dom_time: "30-60 Min",
        attractions_trenta_dom_difficulty: "attractions_difficulty_easy",
        attractions_trenta_dom_family: "attractions_family_yes",
        attractions_trenta_trail_title: "Soča Weg Trenta",
        attractions_trenta_trail_teaser: "Wanderweg entlang der Soča in Trenta. Geeignet für alle Altersgruppen.",
        attractions_trenta_trail_details: "Der Soča Weg in Trenta ist ein Wanderweg entlang der Soča, der für alle Altersgruppen geeignet ist. Der Weg bietet Möglichkeiten für Spaziergänge, Fotografie und Naturgenuss. Die beste Zeit für einen Besuch ist Frühling oder Sommer, wenn das Wetter am schönsten ist. Bringen Sie bequeme Schuhe für das Gehen mit. Achten Sie auf Sicherheit am Wasser - Kinder müssen immer beaufsichtigt werden.",
        attractions_trenta_trail_time: "1-2 Stunden",
        attractions_trenta_trail_difficulty: "attractions_difficulty_easy",
        attractions_trenta_trail_family: "attractions_family_yes",
        attractions_trenta_zadnjica_title: "Zadnjica Tal",
        attractions_trenta_zadnjica_teaser: "Malerisches Tal im Hochgebirge mit schönen Ausblicken. Erreichbar über Bergwege.",
        attractions_trenta_zadnjica_details: "Das Zadnjica Tal ist ein malerisches Tal im Hochgebirge mit schönen Ausblicken auf die umliegenden Berge. Ein Bergweg führt zum Tal und dauert etwa 1-2 Stunden zu Fuß. Die beste Zeit für einen Besuch ist Frühling oder Sommer, wenn das Wetter am schönsten ist. Bringen Sie bequeme Schuhe für Bergwanderungen, zusätzliche Kleidung und viel Wasser mit. Das Wetter im Hochgebirge kann sich schnell ändern, seien Sie daher auf Änderungen vorbereitet.",
        attractions_trenta_zadnjica_time: "1-2 Stunden",
        attractions_trenta_zadnjica_difficulty: "attractions_difficulty_moderate",
        attractions_trenta_zadnjica_family: "attractions_family_care",
        attractions_lepena_lepenjica_title: "Lepenjica Bach",
        attractions_lepena_lepenjica_teaser: "Schöner Bach, der durch Lepena fließt. Möglichkeiten für Spaziergänge am Wasser.",
        attractions_lepena_lepenjica_details: "Der Lepenjica Bach ist ein schöner Bach, der durch Lepena fließt und Möglichkeiten für Spaziergänge am Wasser und Fotografie bietet. Am Bach gibt es Möglichkeiten zur Erholung und Naturgenuss. Die beste Zeit für einen Besuch ist Frühling oder Sommer, wenn das Wasser am schönsten ist. Bringen Sie bequeme Schuhe für das Gehen mit. Achten Sie auf Sicherheit am Wasser - Kinder müssen immer beaufsichtigt werden.",
        attractions_lepena_lepenjica_time: "30-60 Min",
        attractions_lepena_lepenjica_difficulty: "attractions_difficulty_easy",
        attractions_lepena_lepenjica_family: "attractions_family_yes",
