        attractions_zaga_boka_family: "attractions_family_yes",
        attractions_cezsoča_intro: "Čezsoča to obszar wzdłuż Soča z dostępem do licznych piaszczystych i żwirowych brzegów. Idealne dla tych, którzy szukają spokojnych spacerów wzdłuż rzeki.",
        attractions_cezsoča_place_title: "Čezsoča",
        attractions_cezsoča_place_teaser: "Malownicze miasto nad Soča z dostępem do szerokich żwirowych brzegów. Idealne do spacerów i odpoczynku nad wodą.",
        attractions_cezsoča_place_details: "Čezsoča to malownicze miasto nad rzeką Soča, oferujące dostęp do szerokich żwirowych brzegów. Obszar jest doskonały do spacerów nad wodą, odpoczynku i fotografowania. Najlepszy czas na wizytę to lato, gdy woda jest cieplejsza i odpowiednia do pływania. Zabierz strój kąpielowy, jeśli chcesz pływać. Uważaj na bezpieczeństwo nad wodą - dzieci muszą być zawsze nadzorowane. Pogoda może szybko się zmienić, więc zabierz dodatkowe ubranie.",
        attractions_cezsoča_place_time: "30-60 min",
        attractions_cezsoča_place_difficulty: "attractions_difficulty_easy",
        attractions_cezsoča_place_family: "attractions_family_yes",
