        attractions_bovec_boka_family: "attractions_family_yes",
        attractions_bovec_velika_korita_title: "Wielki Wąwóz Soča",
        attractions_bovec_velika_korita_teaser: "Spektakularne zjawisko przyrodnicze, gdzie Soča przecina głębokie kaniony. Dostępne oznakowaną ścieżką z punktami widokowymi.",
        attractions_bovec_velika_korita_details: "Wielki Wąwóz Soča to spektakularne zjawisko przyrodnicze, gdzie rzeka Soča przecina głębokie kaniony. Oznakowana ścieżka z punktami widokowymi prowadzi do wąwozu, zajmując około 1-2 godzin. Najlepszy czas na wizytę to wczesny ranek lub późne popołudnie, gdy światło jest najpiękniejsze. Zabierz wygodne buty do chodzenia po schodach i kamieniach. Uważaj na śliskie kamienie, szczególnie po deszczu. Pogoda może szybko się zmienić, więc zabierz dodatkowe ubranie.",
        attractions_bovec_velika_korita_time: "1-2 godziny",
        attractions_bovec_velika_korita_difficulty: "attractions_difficulty_moderate",
        attractions_bovec_velika_korita_family: "attractions_family_yes",
        attractions_bovec_mala_korita_title: "Mały Wąwóz Soča",
        attractions_bovec_mala_korita_teaser: "Mniejszy, ale równie piękny wąwóz wzdłuż Soča. Łatwiejszy dostęp niż Wielki Wąwóz, odpowiedni dla wszystkich grup wiekowych.",
        attractions_bovec_mala_korita_details: "Mały Wąwóz Soča to mniejszy, ale równie piękny wąwóz wzdłuż rzeki Soča. Łatwiejsza ścieżka prowadzi do wąwozu, zajmując około 30-45 minut spaceru. Wąwóz jest odpowiedni dla wszystkich grup wiekowych i oferuje piękne widoki na szmaragdową wodę. Najlepszy czas na wizytę to wiosna lub lato, gdy woda jest najpiękniejsza. Zabierz wygodne buty do chodzenia. Uważaj na śliskie kamienie przy wodzie. Pogoda może szybko się zmienić, więc zabierz dodatkowe ubranie.",
        attractions_bovec_mala_korita_time: "30-45 min",
        attractions_bovec_mala_korita_difficulty: "attractions_difficulty_easy",
        attractions_bovec_mala_korita_family: "attractions_family_yes",
        attractions_trenta_intro: "Trenta to dolina w wysokich górach, gdzie bierze początek rzeka Soča. Obszar oferuje spektakularne naturalne atrakcje i możliwości górskich spacerów.",
        attractions_trenta_valley_title: "Dolina Trenta",
        attractions_trenta_valley_teaser: "Malownicza dolina w wysokich górach, gdzie bierze początek rzeka Soča. Oferuje piękne widoki i możliwości górskich spacerów.",
        attractions_trenta_valley_details: "Trenta to malownicza dolina w wysokich górach, gdzie bierze początek rzeka Soča. Dolina oferuje piękne widoki na otaczające góry i możliwości górskich spacerów. Najlepszy czas na wizytę to wiosna lub lato, gdy pogoda jest najpiękniejsza. Zabierz wygodne buty do chodzenia i dodatkowe ubranie. Pogoda w wysokich górach może szybko się zmienić, więc bądź przygotowany na zmiany. Uważaj na bezpieczeństwo nad wodą i na górskich ścieżkach.",
        attractions_trenta_valley_time: "1-3 godziny",
        attractions_trenta_valley_difficulty: "attractions_difficulty_moderate",
        attractions_trenta_valley_family: "attractions_family_care",
        attractions_trenta_izvir_title: "Źródło Soča",
        attractions_trenta_izvir_teaser: "Źródło rzeki Soča, jedna z najważniejszych naturalnych atrakcji w dolinie. Dostępne górską ścieżką.",
        attractions_trenta_izvir_details: "Źródło Soča to źródło rzeki Soča, które jest jedną z najważniejszych naturalnych atrakcji w dolinie. Górska ścieżka prowadzi do źródła, zajmując około 1-2 godzin spaceru. Źródło jest dobrze zachowane i oferuje piękne widoki na otaczającą przyrodę. Najlepszy czas na wizytę to wiosna lub lato, gdy pogoda jest najpiękniejsza. Zabierz wygodne buty do górskiego chodzenia i dodatkowe ubranie. Pogoda w wysokich górach może szybko się zmienić, więc bądź przygotowany na zmiany.",
        attractions_trenta_izvir_time: "1-2 godziny",
        attractions_trenta_izvir_difficulty: "attractions_difficulty_moderate",
