        attractions_trenta_zadnjica_title: "Údolí Zadnjica",
        attractions_trenta_zadnjica_teaser: "Malebná údolí ve vysokých horách s krásnými výhledy. Dostupná horskými stezkami.",
        attractions_trenta_zadnjica_details: "Údolí Zadnjica je malebná údolí ve vysokých horách s krásnými výhledy na okolní hory. Horská stezka vede k údolí, trvá přibližně 1-2 hodiny chůze. Nejlepší čas na návštěvu je jaro nebo léto, kdy je počasí nejkrásnější. Přineste pohodlné boty na horskou chůzi, další oblečení a dostatek vody. Počasí ve vysokých horách se může rychle změnit, takže buďte připraveni na změny.",
        attractions_trenta_zadnjica_time: "1-2 hodiny",
        attractions_trenta_zadnjica_difficulty: "attractions_difficulty_moderate",
        attractions_trenta_zadnjica_family: "attractions_family_care",
        attractions_lepena_lepenjica_title: "Potok Lepenjica",
        attractions_lepena_lepenjica_teaser: "Krásný potok protékající Lepenou. Možnosti procházek u vody.",
        attractions_lepena_lepenjica_details: "Potok Lepenjica je krásný potok protékající Lepenou a nabízející možnosti procházek u vody a fotografování. U potoka jsou možnosti odpočinku a užívání si přírody. Nejlepší čas na návštěvu je jaro nebo léto, kdy je voda nejkrásnější. Přineste pohodlné boty na chůzi. Dávejte pozor na bezpečnost u vody - děti musí být vždy pod dohledem.",
        attractions_lepena_lepenjica_time: "30-60 min",
        attractions_lepena_lepenjica_difficulty: "attractions_difficulty_easy",
        attractions_lepena_lepenjica_family: "attractions_family_yes",
        attractions_lepena_walk_title: "Snadná procházková stezka Lepena",
        attractions_lepena_walk_teaser: "Snadná procházková stezka přes Lepenu. Vhodná pro všechny věkové kategorie.",
        attractions_lepena_walk_details: "Snadná procházková stezka přes Lepenu je vhodná pro všechny věkové kategorie a nabízí možnosti procházek, fotografování a užívání si přírody. Stezka trvá přibližně 1-2 hodiny chůze. Nejlepší čas na návštěvu je jaro nebo léto, kdy je počasí nejkrásnější. Přineste pohodlné boty na chůzi. Dávejte pozor na bezpečnost u vody - děti musí být vždy pod dohledem.",
